from flask import Flask, send_from_directory
app = Flask(__name__)

app.config['SEND_FILE_MAX_AGE_DEFAULT'] = 0
app.config['SEND_FILE_MAX_AGE_SECONDS'] = 0

@app.route('/<path:path>')
def send_legacy_file(path):
    try:
        if path.endswith('old_filename'):
            new_filename = path.replace('old_filename', 'new_filename')
            return send_from_directory('uploads', new_filename, as_attachment=True)
        else:
            return send_from_directory('uploads', path, as_attachment=True)
    except FileNotFoundError:
        return "File not found.", 404